question:
What is the output of the following code?

```cpp
#include <iostream>
using namespace std;

class Box {
    public:
        static int count;
        Box() { count++; }
        ~Box() { count--; }
};

int Box::count = 0;

int main() {
    Box b1;
    Box *b2 = new Box();
    cout << Box::count << " ";
    delete b2;
    cout << Box::count;
    return 0;
}
```
